parameters.jsCode:
// Mock CTI feed — ของจริงคือ Schedule Trigger + RSS Read (CISA / The Hacker News)
// จงใจใส่ 2 ข่าวที่เป็น "เรื่องเดียวกันคนละสำนัก" เพื่อ demo dedup ข้ามแหล่งข่าว:
// ข่าวแรกจะได้ status=created ข่าวที่สองต้องได้ status=dedup_hit (อ้าง CVE ชุดเดียวกัน)
return [
  { json: {
      source: 'The Hacker News',
      title: 'New Brute-Force Campaign Targets Active Directory via RDP and Password Spraying',
      link: 'https://thehackernews.com/2026/08/ad-bruteforce-campaign.html',
      published: '2026-08-21T02:10:00Z',
      content: 'Researchers have uncovered a large-scale campaign targeting enterprise Active Directory environments. The attackers perform password spraying (T1110.003) and password guessing (T1110.001) against domain accounts, then move laterally over RDP (T1021.001). Attack traffic originates from 45.155.205[.]233 and 185.220.101[.]45, and tooling is hosted at hxxp://ad-brute-tools[.]top/payload.exe (SHA256: e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855). The campaign abuses weak password policies, and organizations lagging on CVE-2025-21298 patching face elevated risk. Administrators are urged to enforce account lockout policies and monitor failed logon events.'
  }},
  { json: {
      source: 'CISA',
      title: 'CISA Advisory: Ongoing Brute-Force Activity Against Active Directory Environments',
      link: 'https://www.cisa.gov/news-events/alerts/2026/08/21/ad-bruteforce',
      published: '2026-08-21T06:00:00Z',
      content: 'CISA is aware of ongoing brute-force activity targeting Active Directory. Threat actors conduct password spraying (T1110.003) and use RDP (T1021.001) for lateral movement, with activity linked to 45.155.205[.]233. Organizations should prioritize remediation of CVE-2025-21298 and review authentication logs.'
  }}
];

// ประกอบ prompt เชิงรุก: fill_instruction + facts จากข่าว (verbatim) + IoCs + RAG chunks
const intel = $('Limit 1 Story').first().json.intel;
const sec = $('Split Out Sections').item.json;
const rag = $json;

const chunks = (rag.chunks ?? []).map((c, i) => `[${i + 1}] (${c.source_doc})\n${c.text}`).join('\n---\n');
const missing = rag.missing_techniques ?? [];

const factsBlock = (intel.facts ?? []).map((f, i) => `(${i + 1}) ${f}`).join('\n');
const iocLines = [
  ...(intel.iocs.ips ?? []).map(v => `IP: ${v}`),
  ...(intel.iocs.domains ?? []).map(v => `Domain: ${v}`),
  ...(intel.iocs.hashes ?? []).map(v => `Hash: ${v}`),
  ...(intel.iocs.cves ?? []).map(v => `CVE: ${v}`)
].join('\n');

const intelContext = [
  `Threat report: ${intel.threat_name}`,
  `Source: ${intel.feed_name} (${intel.link ?? '-'})`,
  `Techniques: ${intel.mitre_techniques.join(', ')}`
].join('\n');

const missingBlock = missing.length
  ? `\n⚠️ ไม่มีข้อมูลใน knowledge base รองรับ technique: ${missing.join(', ')}\nให้แปะธง ⚠️ ในแถวที่เกี่ยวข้อง และห้ามแต่งขั้นตอนขึ้นเอง`
  : '';

const prompt = `คุณเป็น SOC analyst ที่เขียนแผนป้องกันเชิงรุก (Proactive Defense Playbook) จากข่าวกรองภัยคุกคาม
สำคัญ: องค์กรยังไม่ถูกโจมตี — นี่คือการเตรียมป้องกันล่วงหน้า ไม่ใช่การตอบสนองเหตุการณ์ที่เกิดแล้ว

${sec.fill_instruction}

--- THREAT INTELLIGENCE ---
${intelContext}

--- FACTS จากข่าว (คัดตรงจากต้นฉบับ) ---
${factsBlock || '(ไม่มี)'}

--- IoCs ---
${iocLines || '(ไม่มี)'}

--- KNOWLEDGE BASE (ใช้เฉพาะข้อมูลด้านล่างนี้เท่านั้น ห้ามเพิ่มจากความรู้ตัวเอง) ---
${chunks || '(ไม่พบข้อมูลรองรับ)'}
${missingBlock}

เขียนที่ระดับแนวทาง/วิธีการ (procedure) ไม่ผูกกับ OS ใด OS หนึ่ง ยกคำสั่งเป็นตัวอย่างสั้นๆ ได้แต่ห้ามให้คำสั่งเป็นแกนหลักของขั้นตอน

ตอบเป็นตาราง Markdown เท่านั้น ไม่ต้องมีคำนำหรือคำสรุป`;

return { json: { phase: sec.phase, heading: sec.heading, prompt } };

const text = $json.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
const meta = $('Build Prompt').item.json;

return {
  json: {
    phase: meta.phase,
    heading: meta.heading,
    content: text.trim()
  }
};

// ยุบ 3 items กลับเป็น 1 ก้อน (ฝั่งเชิงรุก — ไม่มี NCSC/CTI enrichment, ใช้ intel + IoC table แทน)
const intel = $('Limit 1 Story').first().json.intel;
const sections = $input.all().map(i => i.json);

const allRag = $('Retrieve Chunks').all().map(i => i.json);
const missing = [...new Set(allRag.flatMap(r => r.missing_techniques ?? []))];

return [{
  json: {
    intel_id: intel.intel_id,
    threat_name: intel.threat_name,
    technique_ids: intel.mitre_techniques,
    severity: 'advisory (proactive)',
    alert: {},
    sections,
    missing_techniques: missing,
    playbook_type: 'proactive',
    intel_source: {
      feed: intel.feed_name,
      title: intel.title,
      link: intel.link,
      published: intel.published
    },
    iocs: intel.iocs
  }
}];

// ก้อนสุดท้าย — สองข้อความพร้อมส่ง แยก field ให้ต่อ Teams/LINE node ในอนาคตได้ทันที
return [{
  json: {
    playbook_id: $('Save Draft').first().json.playbook_id,
    intel_id: $('Aggregate Sections').first().json.intel_id,
    executive_message: $json.executive_message,
    it_message: $json.it_message
  }
}];
